import { useState } from 'react';
import LoadingSpinner from '../components/LoadingSpinner';

const PostJobPage = () => {
  const [loading, setLoading] = useState(false);
  const [jobDetails, setJobDetails] = useState({
    title: '',
    description: '',
    requirements: '',
    salary: '',
    location: '',
    companyLogo: ''
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setJobDetails(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    // Simulate API call
    setTimeout(() => {
      setLoading(false);
      alert('Job posted successfully!');
    }, 2000);
  };

  return (
    <div className="max-w-4xl mx-auto px-4 py-8">
      <h1 className="text-2xl font-semibold text-white mb-6">Post a New Job</h1>
      <form onSubmit={handleSubmit} className="bg-gray-800 p-6 rounded-xl shadow-md">
        <div className="mb-4">
          <label className="block text-gray-400 mb-2">Job Title</label>
          <input
            type="text"
            name="title"
            value={jobDetails.title}
            onChange={handleChange}
            className="w-full p-3 rounded-lg bg-gray-700 text-white"
            required
          />
        </div>
        <div className="mb-4">
          <label className="block text-gray-400 mb-2">Description</label>
          <textarea
            name="description"
            value={jobDetails.description}
            onChange={handleChange}
            className="w-full p-3 rounded-lg bg-gray-700 text-white"
            rows={5}
            required
          />
        </div>
        <div className="mb-4">
          <label className="block text-gray-400 mb-2">Requirements</label>
          <textarea
            name="requirements"
            value={jobDetails.requirements}
            onChange={handleChange}
            className="w-full p-3 rounded-lg bg-gray-700 text-white"
            rows={3}
            required
          />
        </div>
        <div className="mb-4">
          <label className="block text-gray-400 mb-2">Salary Range</label>
          <input
            type="text"
            name="salary"
            value={jobDetails.salary}
            onChange={handleChange}
            className="w-full p-3 rounded-lg bg-gray-700 text-white"
            required
          />
        </div>
        <div className="mb-4">
          <label className="block text-gray-400 mb-2">Location</label>
          <input
            type="text"
            name="location"
            value={jobDetails.location}
            onChange={handleChange}
            className="w-full p-3 rounded-lg bg-gray-700 text-white"
            required
          />
        </div>
        <div className="mb-4">
          <label className="block text-gray-400 mb-2">Company Logo URL</label>
          <input
            type="text"
            name="companyLogo"
            value={jobDetails.companyLogo}
            onChange={handleChange}
            className="w-full p-3 rounded-lg bg-gray-700 text-white"
          />
        </div>
        <button
          type="submit"
          className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition"
          disabled={loading}
        >
          {loading ? <LoadingSpinner /> : 'Submit Job'}
        </button>
      </form>
    </div>
  );
};

export default PostJobPage;

