interface Job {
  id: string;
  title: string;
  company: string;
  location: string;
  salary: string;
  logo: string;
}

const JobCard = ({ job }: { job: Job }) => {
  return (
    <div className="bg-gray-800 p-6 rounded-2xl shadow-md hover:shadow-lg transition">
      <div className="flex items-center mb-4">
        <img
          src={job?.logo || 'https://images.unsplash.com/photo-1506744038136-46273834b3fb?w=400'}
          alt={job?.company || 'Company Logo'}
          className="w-12 h-12 rounded-full mr-4"
        />
        <div>
          <h3 className="text-white font-medium text-lg">{job?.title || 'Job Title'}</h3>
          <p className="text-gray-400 text-sm">{job?.company || 'Company Name'}</p>
        </div>
      </div>
      <p className="text-gray-400 mb-2">Location: {job?.location || 'Unknown'}</p>
      <p className="text-gray-400 mb-4">Salary: {job?.salary || 'Negotiable'}</p>
      <button className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">
        Apply Now
      </button>
    </div>
  );
};

export default JobCard;

